__kernel void
findK(	long maxheight,
		__global knode *knodes,
		long knodes_elem,
		__global record *records,
		__global long *currKnode,
		__global long *offset,
		__global int *keys,
		__global record *ans)
{
	const uint thid = get_local_id(0);
	const uint bid = get_group_id(0);

	__local long l_currKnode;
	__local long l_offset;
	__local int l_key;

	if (thid == 0) {
		l_currKnode = currKnode[bid];
		l_offset = offset[bid];
		l_key = keys[bid];
	}
	barrier(CLK_LOCAL_MEM_FENCE);

	for (long i = 0; i < maxheight; i++) {
		long curr = l_currKnode;
		int key = l_key;

		if (key >= knodes[curr].keys[thid] &&
			key <  knodes[curr].keys[thid + 1]) {
			int next = knodes[curr].indices[thid];
			if (knodes_elem > (long)next) {
				l_offset = (long)next;
			}
		}

		barrier(CLK_LOCAL_MEM_FENCE);

		if (thid == 0) {
			l_currKnode = l_offset;
		}

		barrier(CLK_LOCAL_MEM_FENCE);
	}

	if (l_key == knodes[l_currKnode].keys[thid]) {
		ans[bid].value = records[knodes[l_currKnode].indices[thid]].value;
	}

	barrier(CLK_GLOBAL_MEM_FENCE);

	if (thid == 0) {
		currKnode[bid] = l_currKnode;
		offset[bid] = l_offset;
	}
}

