__kernel void
findRangeK(	long maxheight,
			__global knode *knodes,
			long knodes_elem,
			__global long *currKnode,
			__global long *offset,
			__global long *lastKnode,
			__global long *offset_2,
			__global int *start,
			__global int *end,
			__global int *recstart,
			__global int *reclength)
{
	const uint thid = get_local_id(0);
	const uint bid = get_group_id(0);

	__local long l_currKnode;
	__local long l_offset;
	__local long l_lastKnode;
	__local long l_offset_2;
	__local int l_start;
	__local int l_end;
	__local int l_recstart;
	__local int l_reclength;

	if (thid == 0) {
		l_currKnode = currKnode[bid];
		l_offset = offset[bid];
		l_lastKnode = lastKnode[bid];
		l_offset_2 = offset_2[bid];
		l_start = start[bid];
		l_end = end[bid];
		l_recstart = recstart[bid];
		l_reclength = reclength[bid];
	}
	barrier(CLK_LOCAL_MEM_FENCE);

	for (long i = 0; i < maxheight; i++) {
		long curr = l_currKnode;
		long last = l_lastKnode;
		int s = l_start;
		int e = l_end;

		if ((s >= knodes[curr].keys[thid]) &&
			(s <  knodes[curr].keys[thid + 1])) {
			int next = knodes[curr].indices[thid];
			if (knodes_elem > (long)next) {
				l_offset = (long)next;
			}
		}

		if ((e >= knodes[last].keys[thid]) &&
			(e <  knodes[last].keys[thid + 1])) {
			int next2 = knodes[last].indices[thid];
			if (knodes_elem > (long)next2) {
				l_offset_2 = (long)next2;
			}
		}

		barrier(CLK_LOCAL_MEM_FENCE);

