			l_currKnode = l_offset;
			l_lastKnode = l_offset_2;
		}

		barrier(CLK_LOCAL_MEM_FENCE);
	}

	if (l_start == knodes[l_currKnode].keys[thid]) {
		l_recstart = knodes[l_currKnode].indices[thid];
	}

	barrier(CLK_LOCAL_MEM_FENCE);

	if (l_end == knodes[l_lastKnode].keys[thid]) {
		l_reclength = knodes[l_lastKnode].indices[thid] - l_recstart + 1;
